        $settings=self::art_walk_settings(); ?>
        <div class="wrap"><h1><?php esc_html_e('Artist Growth Settings','elev8-os'); ?></h1><h2><?php esc_html_e('Art Walk Assistant','elev8-os'); ?></h2>
